package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  void setNumberToNumberStrategy_shouldSetStrategyAndReturnThis() throws Exception {
    // Arrange
    ToNumberStrategy mockStrategy = mock(ToNumberStrategy.class);

    // Act
    GsonBuilder returned = gsonBuilder.setNumberToNumberStrategy(mockStrategy);

    // Assert
    assertSame(gsonBuilder, returned, "setNumberToNumberStrategy should return this");
    // Use reflection to verify private field numberToNumberStrategy is set correctly
    Field field = GsonBuilder.class.getDeclaredField("numberToNumberStrategy");
    field.setAccessible(true);
    Object actualStrategy = field.get(gsonBuilder);
    assertSame(mockStrategy, actualStrategy, "numberToNumberStrategy field should be set to the provided strategy");
  }

  @Test
  void setNumberToNumberStrategy_shouldThrowNullPointerException_whenNullPassed() {
    // Arrange
    ToNumberStrategy nullStrategy = null;

    // Act & Assert
    NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
      gsonBuilder.setNumberToNumberStrategy(nullStrategy);
    });
    assertNull(thrown.getMessage());
  }
}
